1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function typePremium(type: string, count: number): number {
18	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
19	    return BLOCK_PREMIUM;
20	  }
21	  return count * (BASE_PREMIUMS[type] ?? 0);
22	}
23	
24	function countByType(items: Array<{ type: string }>): Record<string, number> {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	  }
29	  return counts;
30	}
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const LOYALTY_DISCOUNT_RATE = 0.2;
36	const LOYALTY_THRESHOLD = 2;
37	
38	function surchargeTotal<T extends { type: string }>(
39	  items: T[],
40	  appliesTo: (item: T) => boolean,
41	  rate: number,
42	): number {
43	  let total = 0;
44	  for (const item of items) {
45	    if (appliesTo(item)) {
46	      total += (BASE_PREMIUMS[item.type] ?? 0) * rate;
47	    }
48	  }
49	  return total;
50	}
51	
52	function cursedSurchargeTotal(items: Array<{ type: string; cursed?: boolean }>): number {
53	  return surchargeTotal(items, (item) => !!item.cursed, CURSED_SURCHARGE_RATE);
54	}
55	
56	function highEnchantmentSurchargeTotal(items: Array<{ type: string; enchantment?: number }>): number {
57	  return surchargeTotal(
58	    items,
59	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
60	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
61	  );
62	}
63	
64	function basePremiumTotal(items: Array<{ type: string }>): number {
65	  const countsByType = countByType(items);
66	  let total = 0;
67	  for (const [type, count] of Object.entries(countsByType)) {
68	    total += typePremium(type, count);
69	  }
70	  return total;
71	}
72	
73	function calculateQuotePremium(items: Array<{ type: string; cursed?: boolean; enchantment?: number }>, yearsWithMHPCO: number): number {
74	  const policyBasePremium = basePremiumTotal(items);
75	  const itemAdjustedTotal = policyBasePremium + cursedSurchargeTotal(items) + highEnchantmentSurchargeTotal(items);
76	
77	  const loyaltyDiscount = yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT_RATE : 0;
78	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
79	  const rawPremium = itemAdjustedTotal - loyaltyDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
80	  return Math.ceil(rawPremium);
81	}
82	
83	interface QuoteResult {
84	  premium: number;
85	}
86	
87	interface ScenarioOutcome {
88	  results: QuoteResult[];
89	}
90	
91	export function processScenario(scenario: {
92	  customer: { yearsWithMHPCO: number };
93	  steps: Array<{ op: string; items?: Array<{ type: string; cursed?: boolean; enchantment?: number }> }>;
94	}): ScenarioOutcome {
95	  return {
96	    results: scenario.steps.map((step) => ({
97	      premium: calculateQuotePremium(step.items ?? [], scenario.customer.yearsWithMHPCO),
98	    })),
99	  };
100	}
